 using System.ComponentModel;
 using System.Net;
 using System.Text;
 using System.Text.RegularExpressions;
 using Microsoft.Extensions.AI;
 using OpenAIChatClient = OpenAI.Chat.ChatClient;

 // ── Configuration ───────────────────────────────────────────────────────────
 var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY") ?? "";
 var model  = Environment.GetEnvironmentVariable("OPENAI_MODEL")  ?? "gpt-4o";

 if (string.IsNullOrEmpty(apiKey))
 {
     Console.Error.WriteLine("Error: set the OPENAI_API_KEY environment variable.");
     return 1;
 }

 // ── Shared state ────────────────────────────────────────────────────────────
 var notes      = new List<string>();
 var httpClient = new HttpClient();
 httpClient.DefaultRequestHeaders.UserAgent.ParseAdd("ResearchAgent/1.0");

 // ── Tool definitions ────────────────────────────────────────────────────────

 [Description("Search the web for a given query. Returns the top result snippets.")]
 async Task<string> SearchWeb([Description("The search query")] string query)
 {
     Log("🔎", $"Searching: {query}");

     var url = $"https://html.duckduckgo.com/html/?q={Uri.EscapeDataString(query)}";
     try
     {
         var html = await httpClient.GetStringAsync(url);

         // Extract snippets from the DuckDuckGo HTML results page.
         var snippets = new List<string>();
         foreach (Match m in Regex.Matches(
             html,
             @"class=""result__snippet""[^>]*>(.*?)</(?:a|td|div)>",
             RegexOptions.Singleline | RegexOptions.IgnoreCase))
         {
             var text = WebUtility.HtmlDecode(
                 Regex.Replace(m.Groups[1].Value, "<[^>]+>", "")).Trim();
             if (!string.IsNullOrWhiteSpace(text))
                 snippets.Add(text);
         }

         if (snippets.Count == 0)
             return $"No results found for '{query}'.";

         var sb = new StringBuilder();
         sb.AppendLine($"Search results for '{query}':");
         for (var i = 0; i < Math.Min(snippets.Count, 6); i++)
             sb.AppendLine($"  {i + 1}. {snippets[i]}");
         return sb.ToString();
     }
     catch (Exception ex)
     {
         return $"Search failed: {ex.Message}";
     }
 }

 [Description("Save a research note to remember an important finding.")]
 string TakeNote(
     [Description("Short label for the note")]   string title,
     [Description("Detailed content of the note")] string content)
 {
     notes.Add($"## {title}\n{content}");
     Log("📝", $"Note saved: {title}");
     return $"Note '{title}' saved. Total notes: {notes.Count}.";
 }

 [Description("Retrieve all previously saved research notes.")]
 string GetNotes()
 {
     if (notes.Count == 0)
         return "No notes saved yet.";
     return string.Join("\n\n", notes);
 }

 // ── Build the AI client pipeline ────────────────────────────────────────────
 IChatClient chatClient = new ChatClientBuilder(new OpenAIChatClient(model, apiKey).AsIChatClient())
     .UseFunctionInvocation()
     .Build();

 var tools = new AITool[]
 {
     AIFunctionFactory.Create(SearchWeb),
     AIFunctionFactory.Create(TakeNote),
     AIFunctionFactory.Create(GetNotes),
 };

 // ── Get the research topic ──────────────────────────────────────────────────
 Console.ForegroundColor = ConsoleColor.Cyan;
 Console.WriteLine("🔬 Research Agent");
 Console.WriteLine("═══════════════════════════════════════");
 Console.ResetColor();

 string topic = args.Length > 0
     ? string.Join(" ", args)
     : Prompt("Enter a research topic: ");

 if (string.IsNullOrWhiteSpace(topic))
 {
     Console.Error.WriteLine("No topic provided.");
     return 1;
 }

 Console.WriteLine($"\n🔍 Researching: {topic}");
 Console.ForegroundColor = ConsoleColor.DarkGray;
 Console.WriteLine("   Agent is working…\n");
 Console.ResetColor();

 // ── Run the agent ───────────────────────────────────────────────────────────
 const string systemPrompt = """
     You are a thorough research agent. Given a topic you must:

     1. SEARCH – call SearchWeb at least 3 times with varied queries to explore
        different angles of the topic.
     2. TAKE NOTES – after each search, call TakeNote to record the key findings.
        Save at least 3 notes covering different aspects.
     3. REVIEW – call GetNotes to review everything you collected.
     4. SUMMARIZE – produce a well-structured final summary containing:
        • Overview paragraph
        • Key findings organised by theme
        • Important data points
        • Brief conclusion

     Always search before summarising. Be systematic and thorough.
     """;

 var messages = new List<ChatMessage>
 {
     new(ChatRole.System, systemPrompt),
     new(ChatRole.User, $"Research the following topic and provide a comprehensive summary: {topic}"),
 };

 var response = await chatClient.GetResponseAsync(messages, new ChatOptions { Tools = [.. tools] });

 // ── Print the final summary ─────────────────────────────────────────────────
 Console.ForegroundColor = ConsoleColor.Green;
 Console.WriteLine("\n═══════════════════════════════════════");
 Console.WriteLine("📋 RESEARCH SUMMARY");
 Console.WriteLine("═══════════════════════════════════════\n");
 Console.ResetColor();

 Console.WriteLine(response.Text);

 Console.ForegroundColor = ConsoleColor.DarkGray;
 Console.WriteLine($"\n[Notes collected: {notes.Count} | Model: {model}]");
 Console.ResetColor();

 return 0;

